	int now=1;
	for(int i=0;i<=63;i++){
		int _=-1;
		for(int j=now;j<=n;j++)if(cd[j]&val[i]){_=j;break;}
		if(_!=now)swap(cd[_],cd[now]);
		for(int j=now+1;j<=n;j++)if(cd[j]&val[i])cd[j]^=cd[now];
		now++;
	}
	sort(cd+1,cd+n+1);
	for(int i=1;i<=n/2;i++)swap(cd[i],cd[n-i+1]);
	for(int i=1;i<=n;i++){
		if(cd[i]==0){n=i-1;break;}
		for(int j=0;j<=63;j++)bit[i][j]=cd[i]&1,cd[i]>>=1;
	}
}
