bool cd[6][67]={0};
	for(int i=1;i<=K;i++){
		for(int j=1;j<=n;j++)
		cd[i][j]=bit[j][num[i]];
		cd[i][n+1]=1;
	}
	int now=1;
	for(int i=1;i<=n;i++){
		int _=-1;
		for(int j=now;j<=K;j++)if(cd[j][i]){_=j;break;}
