inline int read() {
    char ch = getchar();
    ri int x = 0, f = 1;
    while  (ch < '0' || ch > '9') {
        if (ch == '-') f = -1;
        ch = getchar();
    }
    while ('0' <= ch && ch <= '9') {
        x = x * 10 + ch - '0';
        ch = getchar();
    }
    return x * f;
}
void write(ll x) {
    ri ll y = 10,len = 1;
    while (y <= x) { y *= 10; len++; }
    while (len--) { y /= 10; putchar(x/y+48); x %= y; }
}
struct Query {
    int l,r,num,c;
    inline bool operator < (Query cmp) const {
        if (dfn[l]/block != dfn[cmp.l]/block) return dfn[l]/block < dfn[cmp.l]/block;
        if (dfn[r]/block != dfn[cmp.r]/block) return dfn[r]/block < dfn[cmp.r]/block;
        return c < cmp.c;
    }
