    ri ll LCA  = lca(q[1].l,q[1].r),curl = q[1].l,curr = q[1].r,curc = 0,l = curl,r = curr;
    while (l != LCA) reverse(l),l = father[l][0];
    while (r != LCA) reverse(r),r = father[r][0];
