const int mod = 998244353;
void add(int &a, int b){a += b; (a >= mod) && (a -= mod);}
void sub(int &a, int b){a -= b; (a < 0) && (a += mod);}
void mul(int &a, int b){a = (ll)a * b % mod;}
int Add(int a, int b){a += b; return a >= mod ? a - mod : a;}
int Sub(int a, int b){a -= b; return a < 0 ? a + mod : a;}
int Mul(int a, int b){return (ll)a * b % mod;}
int qpow(int a, int b){int ans = 1; while (b) {if (b & 1) ans = (ll)ans * a % mod; a = (ll)a * a % mod; b >>= 1;} return ans;}

const int N = 3005;
int n;
char Map[N][N];
int e[N][N];
vector<int> G[N], rG[N], adj[N];
int d[N], bans[N];
int sta[N], top = 0, low[N], dfn[N], sccno[N], sccnum = 0, tim = 0;
int nodes[N], deg[N], ban[N], vis[N];
bitset<3005> B[N];
void add_edge(int x, int y)
{
	G[x].push_back(y);
}

void run(int x)
{
	vis[x] = 1;
	for (int i = 0; i < sz(G[x]); ++i)
	{
		int to = G[x][i];
		if (vis[to]) continue;
		run(to);
	}
}

void dfs(int x)
{
	low[x] = dfn[x] = ++tim;
	sta[++top] = x;
	for (int i = 0; i < sz(G[x]); ++i)
	{
		int to = G[x][i];
		if (!dfn[to])
		{
			dfs(to);
			checkmin(low[x], low[to]);
		}
		else if (!sccno[to])
		{
			checkmin(low[x], dfn[to]);
		}
	}
	if (low[x] == dfn[x])
	{
		++sccnum;
		while (1)
		{
			int t = sta[top--];
			sccno[t] = sccnum;
			++nodes[sccnum];
			if (t == x) break;
		}
	}
}

void bfs()
{
	queue<int> q;
	for (int i = 1; i <= sccnum; ++i) if (nodes[i] > 1) q.push(i);
	while (!q.empty())
	{
		int x = q.front(); q.pop();
		bans[x] = 1;
		for (int i = 0; i < sz(rG[x]); ++i)
		{
			int to = rG[x][i];
			if (bans[to]) continue;
			q.push(to);
		}
	}
}

void init()
{
	read(n);
	for (int i = 1; i <= n; ++i)
	{
		scanf("%s", Map[i] + 1);
		Map[i][i] = '1';
		for (int j = 1; j <= n; ++j) if (Map[i][j] == '0') add_edge(i, j);
	}
	for (int i = 1; i <= n; ++i)
	{
		if (sccno[i]) continue;
		dfs(i);
	}
	for (int i = 1; i <= n; ++i)
	{
		for (int j = 1; j <= n; ++j) if (Map[i][j] == '0')
		{
			e[sccno[i]][sccno[j]] = 1;
		}
	}
	for (int i = 1; i <= sccnum; ++i)
	{
		for (int j = 1; j <= sccnum; ++j) if ((i ^ j) && e[i][j])
		{
			rG[j].push_back(i);
			++d[i];
		}
	}
	bfs();
	for (int i = 1; i <= n; ++i) ban[i] = bans[sccno[i]];
	for (int i = 1; i <= n; ++i)
	{
		for (int j = 1; j <= n; ++j) if (Map[i][j] == '0')
		{
			if (ban[i] || ban[j]) continue;
			adj[i].push_back(j);
		}
	}
}

void solve()
{
	queue<int> q;
	int m = 0;
	for (int i = 1; i <= n; ++i) 
	{
		B[i].set(i);
		if (deg[i] == 0 && !ban[i]) q.push(i);
		if (!ban[i]) ++m;
	}
	while (!q.empty())
	{
		int x = q.front(); q.pop();
		for (int i = 0; i < sz(adj[x]); ++i)
		{
			int to = adj[x][i];
			B[to] |= B[x];
			if ((--deg[to]) == 0)
			{
				q.push(to);
			}
		}
	}
	int ans1 = 0, ans2 = 0;
	for (int i = 1; i <= n; ++i) if (!ban[i])
	{
		int x = B[i].count();
		add(ans1, Mul(Sub(qpow(2, x), 1), qpow(2, m - x)));
		add(ans2, qpow(2, m - x));
	}
	printf("%d %d\n", ans1, ans2);
}

int main()
{
	init();
	solve();
	return 0;
}

