typedef long long i64;

inline void check(i64 &lhs, i64 rhs) { lhs = (lhs < rhs ? lhs : rhs); }
int gcd(int a, int b) { return b ? gcd(b, a % b) : a; }

const int N = 1000000 + 10;
const i64 INF = 0x3f3f3f3f3f3f3f3f;

int n;
char s[N];

int extract(int s, int step, int mod, const i64 f[], int res[]) {
  int cnt = 0, j = s, k = 0;
  do {
    res[cnt] = j;
    if (f[j] < f[res[k]]) k = cnt;
    ++cnt;
    j = (j + step) % mod;
  } while (j != s);
  std::rotate(res, res + k, res + cnt);
  return cnt;
}

int mod;
i64 f[N];

void update(int m) {
  static i64 g[N];
  int t = gcd(mod, m);
  for (int i = 0; i < m; ++i) g[i] = INF;
  for (int i = 0; i < mod; ++i) check(g[f[i] % m], f[i]);
  for (int i = 0; i < t; ++i) {
    static int cur[N];
    int cnt = extract(i, mod, m, g, cur);
    for (int j = 1; j < cnt; ++j) check(g[cur[j]], g[cur[j - 1]] + mod);
  }
  mod = m;
  memcpy(f, g, mod * sizeof(i64));
}

int pool[4 * N], *top;

void solve(int d, int t) {
  int c = gcd(d, mod);
  static i64 g[N];
  for (int i = 0; i < c; ++i) {
    static int cur[N];
    int cnt = extract(i, d, mod, f, cur);
    static int q[N];
    int l = 1, r = 0;
    for (int j = 0; j < cnt; ++j) {
      while (l <= r && (j - q[l]) * d > t) ++l;
      if (l <= r) check(f[cur[j]], g[cur[q[l]]] + (j - q[l]) * d);
      g[cur[j]] = f[cur[j]] + mod;
      while (l <= r && g[cur[q[r]]] - q[r] * d >= g[cur[j]] - j * d) --r;
      q[++r] = j;
    }
  }
}

int main() {
  int tcase;
  for (scanf("%d", &tcase); tcase--;) {
    i64 w;
    scanf("%d%lld %s", &n, &w, s + 1);
    memset(f, 0x3f, sizeof f);
    f[0] = mod = n;
    static int next[N];
    next[1] = 0;
    for (int i = 2, j = 0; i <= n; ++i) {
      while (j && s[j + 1] != s[i]) j = next[j];
      if (s[j + 1] == s[i]) ++j;
      next[i] = j;
    }
    std::vector<int> b;
    for (int i = next[n]; i; i = next[i]) b.push_back(n - i);
    for (int i = 0; i < b.size();) {
      int j = i + 1;
      update(b[i]);
      if (j == b.size()) break;
      int det = b[j] - b[i], k = j;
      while (k + 1 < b.size() && b[k + 1] - b[k] == det) ++k;
      solve(b[j] - b[i], b[k] - b[i]);
      i = k + 1;
    }
    i64 ans = 0;
    for (int i = 0; i < mod; ++i) if (f[i] <= w) ans += (w - f[i]) / mod + 1;
    printf("%lld\n", ans);
  }
  return 0;
}

