	   if(l<=(j+k>>1))
	     p=ask(i<<1,j,j+k>>1,l,r);
	   if(r>(j+k>>1))
	     p+=ask(i<<1|1,(j+k>>1)+1,k,l,r);
	   return p;
      }
}
inline void make(int i,int j,int k,int l,int r,int x)
{
	if(l<=j && k<=r)
	  {
	   g[i]=(k-j+1)*x;
	   h[i]=x;
      }	   
	else
	  {
	   if(h[i]>=0)
	     {
	      g[i<<1]=g[i<<1|1]=(k-j+1>>1)*h[i];
	      h[i<<1]=h[i<<1|1]=h[i];
	      h[i]=-1;
	     }
	   if(l<=(j+k>>1))
	     make(i<<1,j,j+k>>1,l,r,x);
	   if(r>(j+k>>1))
	     make(i<<1|1,(j+k>>1)+1,k,l,r,x);
	   g[i]=g[i<<1]+g[i<<1|1];
      }
}
inline void tree(int i,int j,int k,int l,int r,int x)
{
	if(l<=j && k<=r)
	  {
	   a[i].insert(-x);
	   f[i]++;
      }
	else
	  {
	   if(l<=(j+k>>1))
	     tree(i<<1,j,j+k>>1,l,r,x);
	   if(r>(j+k>>1))
	     tree(i<<1|1,(j+k>>1)+1,k,l,r,x);
      }
}
inline int tree_(int i,int j,int k,int x,int u)
{
	int p=0;
	if(f[i])
	  p=*a[i].begin();
	if(!u)
	  {
	   if(f[i])
	     {
	      a[i].erase(p);
	      u=p;
	      f[i]--;
	      if(f[i])
	        p=*a[i].begin();
	      else
	        p=0;
	     }
      }
	else if(p<u)
	  {
	   a[i].erase(p);
	   a[i].insert(u);
	   u=p;
	   p=*a[i].begin();
      }
	if(j==k)
	  return -p;
	else
	  {
	   int q;
	   if(x<=(j+k>>1))
	     {
	      if(u)
	        {
	         a[i<<1|1].insert(u);
	         f[i<<1|1]++;
	        }
	      q=tree_(i<<1,j,j+k>>1,x,u);
	     }
	   else
	     {
	      if(u)
	        {
	         a[i<<1].insert(u);
	         f[i<<1]++;
	        }
	      q=tree_(i<<1|1,(j+k>>1)+1,k,x,u);
	     }
	   return max(-p,q);
      }
}
