pii ansfr;

static i64 pre[MAXN];

Decimal print(const pii &sta) {
    if (sta.y == 0) return Decimal(h[0]);
    pii from = fr[sta.x][sta.y];
    Decimal res = print(from);
    if (sta.y == from.y)
        return res;
    else {
        int i = sta.x, j = from.x;
        return (pre[i] - pre[j] + res) / (i - j + 1);
    }
}

void solve()
{
    static f64 dp[MAXN][2];
    static f64 ans;
    
    std::sort(h + 1, h + n);
    ans = pre[0] = h[0];
    ansfr = mk(0, 0);
    
    REP (i, 1, n) pre[i] = pre[i - 1] + h[i];
    REP (i, 0, n) dp[i][0] = h[0];

    int LAST = n;
    REP (k, 1, std::min(K + (1), n)) {
        int MAX = 0;
        REP (i, 1, n) {
            dp[i][k & 1] = dp[i - 1][k & 1];
            fr[i][k] = fr[i - 1][k];
            REP (j, std::max(0, i - LAST - 1), i)
                if (chkmax0(dp[i][k & 1], (pre[i] - pre[j] + dp[j][(k & 1) ^ 1]) / (i - j + 1)))
                    fr[i][k] = mk(j, k - 1);
            if (chkmax0(ans, dp[i][k & 1]))
                ansfr = mk(i, k);

            if (fr[i][k].y == k - 1)
                chkmax(MAX, i - fr[i][k].x);
        }
        LAST = MAX;
        // DISP(MAX, '\n');
    }
    std::cout << print(ansfr).to_string(p) << std::endl;
}

