int qpow(int a,int b)
{
	int x=a;  a=1;
	while (b)
		{
			if (b&1)  a=1LL*a*x%mo;
			x=1LL*x*x%mo,b>>=1;
		}
	return a;
}

void mul(int *a,int *b,int *c)
{
	for (int i=0; i<2*k; i++)  c[i]=0;
	for (int i=0; i<k; i++)
		for (int j=0; j<k; j++)
			c[i+j]=(c[i+j]+1LL*a[i]*b[j])%mo;
	for (int i=2*k-2; i>=k; i--)
		{
			for (int j=1; j<=k; j++)
				c[i-j]=(c[i-j]+1LL*c[i]*g[j])%mo;
			c[i]=0;
		}
}

int* matrixpow(int b)
{
	for (int i=0; i<2*k; i++)  _a[i]=_b[i]=_c[i]=0;
	int *a=_a,*x=_b,*t=_c;
	a[0]=1,x[1]=1;
	while (b)
		{
			if (b&1)  mul(a,x,t),swap(a,t);
			mul(x,x,t),swap(x,t),b>>=1;
		}
	return a;
}

