	k++;
	for (int i=1; i<=k; i++)  g[i]=1LL*f[i-1][1]*qpow(p,i-1)%mo*(mo+1-p)%mo;
	int *a=matrixpow(n),sum=0;
	for (int i=0; i<k; i++)
		sum=(sum+1LL*a[i]*f[i][0])%mo;
	return sum;
