const int MAXN=605,A=500000;

int n,m;
ll b[MAXN][MAXN],a[MAXN][MAXN];
int q[MAXN*MAXN];
ll dis[MAXN*2];
bool inq[MAXN*2];
int num[MAXN*2];
bool spfa()
{
	memset(dis,0x3f,sizeof(dis));
	memset(inq,0,sizeof(inq));
	memset(num,0,sizeof(num));
	int front=1,rear=0;
	dis[1]=0,q[++rear]=1,inq[1]=1,++num[1];
	while(front<=rear)
	{
		int u=q[front++];
		inq[u]=0;
		if(u<=n)
		{
			for(int j=1;j<=m;++j)
				if(dis[j+n]>dis[u]+A+a[u][j])
				{
					dis[j+n]=dis[u]+A+a[u][j];
					if(!inq[j+n])
					{
						q[++rear]=j+n,inq[j+n]=1;
						++num[j+n];
						if(num[j+n]>=n+m)return 0;
					}
				}
		}
		else
		{
			for(int i=1;i<=n;++i)
				if(dis[i]>dis[u]+A-a[i][u-n])
				{
					dis[i]=dis[u]+A-a[i][u-n];
					if(!inq[i])
					{
						q[++rear]=i,inq[i]=1;
						++num[i];
						if(num[i]>=n+m)return 0;
					}
				}
		}
	}
	return 1;
}

void solve()
{
	memset(a,0,sizeof(a));
	readint(n),readint(m);
	for(int i=1;i<n;++i)
		for(int j=1;j<m;++j)
			readint(b[i][j]),b[i][j]-=4*A;
	for(int i=n-1;i;--i)
		for(int j=m-1;j;--j)
			a[i][j]=b[i][j]-a[i+1][j]-a[i][j+1]-a[i+1][j+1];
	for(int i=1;i<=n;++i)
		for(int j=1;j<=m;++j)
			if((i+j)&1)a[i][j]=-a[i][j];
	if(!spfa()){printf("NO\n");return;}
	for(int i=1;i<=n;++i)
		for(int j=1;j<=m;++j)
			a[i][j]+=dis[i]-dis[j+n];
	for(int i=1;i<=n;++i)
		for(int j=1;j<=m;++j)
			if((i+j)&1)a[i][j]=-a[i][j];
	printf("YES\n");
	for(int i=1;i<=n;++i)
	{
		for(int j=1;j<=m;++j)
			printf("%lld ",a[i][j]+A);
		putchar('\n');
	}
}

int main()
{
	int T;
	readint(T);
	while(T--)solve();
	return 0;
}

