  c[0] = a[0] ^ b[0];
  for (int i = 1; i < n; ++i) {
    c[i] = a[i] ^ b[i] ^ carry;
    carry = (a[i] & b[i]) | ((a[i] | b[i]) & carry);
  }
  c[n] = carry;
}

vector<u128> bit_sum(const u128 *l, const u128 *r) {
  static u128 v[2][B];
  for (int i = 0, li = r - l; i < li; i += 2)
    bit_add_1(l + i, l + i + 1, v[0] + i, 1);
  int len = 2;
  for (int i = (r - l) >> 1; i > 1; i >>= 1, ++len) {
    u128 *f = v[len & 1], *g = v[(len & 1) ^ 1];
    for (int j = 0, li = (i >> 1); j < li; ++j, f += 2 * len, g += len + 1)
      bit_add_1(f, f + len, g, len);
  }
  return vector<u128>(v[len & 1], v[len & 1] + len);
}

void tag_and(int b, u128 T) {
  if (zero[b]) return;
  vector<u128> &v = bsum[b];
  tag[b] &= T; sum[b] = 0;
  for (int i = 0, li = v.size(); i < li; ++i) {
    v[i] &= T;
    sum[b] += v[i] << i;
  }
}

void down(int b) {
  if (tag[b] == (u128)-1) return;
  const int l = b * B, r = (b + 1) * B;
  u128 T = tag[b];
  tag[b] = -1;
  for (int i = l; i != r; ++i)
    a[i] &= T;
}

void up(int b) {
  const int l = b * B, r = (b + 1) * B;
  bsum[b] = bit_sum(a + l, a + r);
  const vector<u128> &v = bsum[b];
  u128 OR = 0;
  sum[b] = 0;
  for (int i = 0, li = v.size(); i < li; ++i) {
    sum[b] += v[i] << i;
    OR |= v[i];
  }
  zero[b] = !OR;
}

void division(int b, u128 T) {
  down(b);
  const int l = b * B, r = (b + 1) * B;
  for (int i = l; i != r; ++i)
    a[i] /= T;
  up(b);
}

template<u128 T>
void division_T(int b) {
  down(b);
  const int l = b * B, r = (b + 1) * B;
  for (int i = l; i != r; ++i)
    a[i] /= T;
  up(b);
}

void division_1(int b, u128 T) {
  if (zero[b]) return;
  switch (T) {
    case 2: division_T<2>(b); break;
    case 3: division_T<3>(b); break;
    case 4: division_T<4>(b); break;
    case 5: division_T<5>(b); break;
    case 6: division_T<6>(b); break;
    case 7: division_T<7>(b); break;
    case 8: division_T<8>(b); break;
    default: division(b, T);
  }
}

