struct node{
	int x,sl,sr;
	long long ave,SS;
	long long pred;
	bool operator <(const node &a)const{
		return pred>a.pred;
	}
};
priority_queue<node> Q;
long long Pred(int x,int sl,int sr,long long ave,long long SS){
	for (int i=x;i<=*q;i++)
		for (int j=1;j<=S[q[i]];j++){
			if (ave<0){
				sl+=q[i]; ave+=sl; SS+=sl*sl;
			}
			else{
				sr+=q[i]; ave-=sr; SS+=sr*sr;
			}
		}
	return SS*n-ave*ave;
}
int main(){
	ans=1ll<<60;
	scanf("%d",&n);
	for (int i=1;i<=n;i++)
		scanf("%d",&a[i]);
