void walk(pii &t,int &v,int k0,int k1,int j0,int j1,int qwq)
{
	node tmp=mkp(v,t);
//	cout<<"walk "<<v<<' '<<t.fi<<' '<<t.se<<endl;
	For(i,1,k0){
		int pos=j0+i;
		node val=tmp;
		tmp.fi += 2*qwq*(n-pos+1)*val.se.fi;
		tmp.fi += 2*qwq*(pos-1)*val.se.se;
		tmp.fi += qwq*qwq*(n-pos+1)*(pos-1);
		tmp.se.fi += qwq*(pos-1);
	}
	For(i,1,k1){
		int pos=j1-i;
		node val=tmp;
		tmp.fi += 2*qwq*(n-pos+1)*val.se.fi;
		tmp.fi += 2*qwq*(pos-1)*val.se.se;
		tmp.fi += qwq*qwq*(n-pos+1)*(pos-1);
		tmp.se.se += (n-pos+1)*qwq;
	}
	t=tmp.se;
	v=tmp.fi;
}

