#include <bits/stdc++.h>
using namespace std;
using i64 = long long;
using i128 = __int128;
constexpr int N = 1e5 + 10;
constexpr i64 mod = 999999999999989;
i64 pwr[N];
int k;
struct Tree {
	int n, rt, dep[N], leaf[N], fa[N], sz[N];
	i64 f[N];
	vector<int> G[N];
	vector<int> id[N];
	void read() {
		cin >> n;
		for(int i = 1; i <= n; i ++) {
			cin >> fa[i];
			if(fa[i] != -1) G[fa[i]].emplace_back(i);
			else rt = i;
		}
	}
	void dfs(int u) {
		leaf[u] = G[u].empty();
		id[dep[u]].emplace_back(u);
		sz[u] = 1;
		for(auto v : G[u]) {
			dep[v] = dep[u] + 1;
			dfs(v);
		}
		sort(G[u].begin(), G[u].end(), [&] (int u, int v) {return sz[u] == sz[v] ? f[u] > f[v] : sz[u] > sz[v];});
		f[u] = dep[u];
		for(auto v : G[u]) {
			f[u] = (f[u] + (i128) pwr[sz[u]] * f[v]) % mod;
			sz[u] += sz[v];
		}
	}
	void clear() {
		for(int i = 1; i <= n; i ++) id[i].clear(), dep[i] = 0, G[i].clear();
	}
}t1, t2;
bool work(int rt1, int rt2) {
	// if(k < 0) return false;
	if(!rt2) return true;
	if(t1.G[rt1].size() < t2.G[rt2].size()) return false;
	vector<i64> x, y;
	for(auto u : t1.G[rt1]) x.emplace_back(t1.f[u]);
	for(auto u : t2.G[rt2]) y.emplace_back(t2.f[u]);
	sort(x.begin(), x.end());
	sort(y.begin(), y.end());
	if(x != y) {
		map<i64, vector<int>> mp;
		for(auto u : t1.G[rt1]) mp[t1.f[u]].emplace_back(u);
		vector<int> sonx, sony;
		for(auto u : t2.G[rt2]) {
			if(!mp.count(t2.f[u]) || mp[t2.f[u]].empty()) {
				sony.emplace_back(u);
			}
			else mp[t2.f[u]].pop_back();
		}
		for(auto [a, b] : mp) for(auto t : b) sonx.emplace_back(t);
		while(sony.size() < sonx.size()) sony.emplace_back(0);
		sort(sonx.begin(), sonx.end());
		do {
			int flag = 1;
			for(int i = 0; i < sonx.size() && flag; i ++) flag &= work(sonx[i], sony[i]);
			if(flag) return true;
		}while(next_permutation(sonx.begin(), sonx.end()));
		return false;
	}
	return true;
}
