ll qPow(ll a,ll b){
	ll ans=1;
	while(b){
		if(b%2) ans=ans*a;
		a=a*a;
		b/=2;
	}
	return ans;
}

ll my_sqrt(ll a,ll b){
	long double ans=powl(a,1.0/b);
	for(int i=ans+3;;i--){
		double aa=powl(i,b);
		if(aa>2*a) continue;
		if(qPow(i,b)<=a) return i;
	}
}

