  cin >> sid >> n >> k >> m;
  for(int i = 2; i <= n; i++) cin >> fa[i], e[fa[i]].push_back(i);
  dfs1(1), dfs2(1, 0);
  for(int i = 1; i <= k; i++) cin >> emp[i].first >> emp[i].second;
  for(int i = 1; i <= m; i++) {
    int op, id;
    cin >> op;
    if(op == 1) {
      lst[++k] = i;
      cin >> emp[k].first >> emp[k].second;
    }
    else {
      cin >> id;
      modify(0, m, lst[id], i - 1, 1, id);
      lst[id] = -1;
    }
  }
  for(int i = 1; i <= k; i++) {
    if(lst[i] == -1) continue;
    modify(0, m, lst[i], m, 1, i);
  }
  tr1.build(1, n, 1, 0);
  tr2.build(1, n, 1, 1);
  solve(0, m, 1);
  cerr << 1e3 * clock() / CLOCKS_PER_SEC << " ms\n";
  return 0;
}
