#define double long double
const size_t maxN = 300005;

std::mt19937 gen((std::random_device())());
const double pi = std::acos(-1.0);
double ang = std::uniform_real_distribution<>(-pi, pi)(gen);
double sina = std::sin(ang), cosa = std::cos(ang);

int N;
double X[maxN], Y[maxN];
int R[maxN], ind[maxN];
int Ans[maxN];

struct node
{
	int i;
	double mn[2], mx[2];
	node *lc, *rc;
	void pushup()
	{
		mn[0] = X[i] - R[i], mx[0] = X[i] + R[i];
		mn[1] = Y[i] - R[i], mx[1] = Y[i] + R[i];
		if (lc)
		{
			for (int j = 0; j != 2; ++j)
			{
				mn[j] = std::min(mn[j], lc->mn[j]);
				mx[j] = std::max(mx[j], lc->mx[j]);
			}
		}
		if (rc)
		{
			for (int j = 0; j != 2; ++j)
			{
				mn[j] = std::min(mn[j], rc->mn[j]);
				mx[j] = std::max(mx[j], rc->mx[j]);
			}
		}
	}
} nodeBuf[maxN], *root;

#define node(x) (nodeBuf + x)
void build(node *&o, int l, int r, int d)
{
	if (l > r)
	{
		o = nullptr;
		return;
	}
	int m = l + r >> 1;
	std::nth_element(nodeBuf + l, nodeBuf + m, nodeBuf + r + 1, d == 0 ? [](const node &x, const node &y) { return X[x.i] < X[y.i]; } : [](const node &x, const node &y) { return Y[x.i] < Y[y.i]; });
	o = node(m);
	build(o->lc, l, m - 1, d ^ 1);
	build(o->rc, m + 1, r, d ^ 1);
	o->pushup();
}

inline double sqr(double x)
{
	return x * x;
}

inline double getDist(int x, int y)
{
	return std::sqrt(sqr(X[x] - X[y]) + sqr(Y[x] - Y[y]));
}

void erase(node *o, int i, int r)
{
	if (!o)
		return;
	if (o->mx[0] < X[i] - r || o->mn[0] > X[i] + r || o->mx[1] < Y[i] - r || o->mn[1] > Y[i] + r)
		return;
	if (!Ans[o->i] && getDist(o->i, i) <= R[o->i] + r + 1e-6)
	{
		Ans[o->i] = i;
		R[o->i] = -2e9;
	}
	erase(o->lc, i, r);
	erase(o->rc, i, r);
	o->pushup();
}

int main()
{
	scanf("%d", &N);
	for (int i = 1, x, y, r; i <= N; ++i)
	{
		scanf("%d%d%d", &x, &y, &r);
		X[i] = x * cosa - y * sina, Y[i] = x * sina + y * cosa, R[i] = r;
		ind[i] = i;
	}

	std::stable_sort(ind + 1, ind + 1 + N, [](int x, int y) { return R[x] > R[y]; });

	for (int i = 1; i <= N; ++i)
		node(i)->i = i;

	build(root, 1, N, 0);

	for (int i = 1; i <= N; ++i)
		if (!Ans[ind[i]])
			erase(root, ind[i], R[ind[i]]);

	for (int i = 1; i <= N; ++i)
		printf("%d%c", Ans[i], " \n"[i == N]);

	return 0;
}

