//self

inline bool IsRoot(int o) {
  return ch[fa[o]][0] != o && ch[fa[o]][1] != o;
}

void Rev(int o) {
  std::swap(lc, rc);
  filp[o] ^= 1;
}

inline void PushDown(int o) {
  if(filp[o]) {
    if(lc) Rev(lc);
    if(rc) Rev(rc);
    filp[o] = false;
  }
}

inline void PushUp(int o) {
  sum[o] = val[o] ^ son[o] ^ sum[lc] ^ sum[rc];
}

inline void Rot(int o) {
  int fo = fa[o], ffo = fa[fo];
  int fd = ch[fo][1] == o, ffd = ch[ffo][1] == fo;
  int s = ch[o][fd^1];

  if(!IsRoot(fo)) ch[ffo][ffd] = o;
  fa[o] = ffo; ch[o][fd^1] = fo;
  fa[fo] = o; ch[fo][fd] = s;
  fa[s] = fo; PushUp(fo);
}

int st[maxN], top;
void Splay(int o) {
  for(int u = st[++top] = o; !IsRoot(u); u = fa[u])
    st[++top] = fa[u];
  while(top) PushDown(st[top--]);

  while(!IsRoot(o)) {
    int fo = fa[o], ffo = fa[fo];

    if(!IsRoot(fo))
      Rot((ch[ffo][1] == fo) == (ch[fo][1] == o) ? fo : o);
    Rot(o);
  }
  PushUp(o);
}

void Access(int o) {
  for(int t = 0; o; t = o, o = fa[o]) {
    Splay(o); son[o] ^= sum[rc] ^ sum[t]; rc = t; PushUp(o);
  }
}

void ChangeRoot(int o) {
  Access(o); Splay(o); Rev(o);
}
  
void Link(int o1,int o2) {
  ChangeRoot(o1);
  Access(o2);
  Splay(o2);
  fa[o1] = o2;
  son[o2] ^= sum[o1];
  PushUp(o2);
}

void Cut(int o1,int o2) {
  ChangeRoot(o1);
  Access(o2); Splay(o2);
  fa[o1] = ch[o2][0] = 0;
  PushUp(o2);
}

void Modify(int o,LL v) {
  Access(o); Splay(o);
  val[o] ^= v; PushUp(o);
}

