    if (l==r) {
        st[p] += mark[p];
        mark[p] = 0;
    }
    else {
        mark[(p<<1)] += mark[p];
        mark[(p<<1)|1] += mark[p];
        st[p] += mark[p];
        mark[p] = 0;
    }
}

    void range_update(int p,int l,int r,int a,int b,int v){
            rm(p,l,r);

            if (a>r || b<l) return;
		            if (l==r) {
                st[p]+=v;
                return;
            }
            if (a<=l && b>=r) {
                st[p] += v;
                mark[(p<<1)]+= v;
                mark[(p<<1)|1]+= v;
            }
            else {
                int mid = (l+r)/2;
                range_update((p<<1),l,mid,a,b,v);
                range_update((p<<1)|1,mid+1,r,a,b,v);
                st[p] = max(st[(p<<1)],st[(p<<1)|1]);
            }
    }

    int rmq(int p,int l,int r,int a,int b){
        rm(p,l,r);

        if (a>r || b<l) return 0;
		  	if (l==r) return st[p];
        if (a<=l && b>=r) {
           return st[p];
        }
        else {
            int mid = (l+r)/2;
            int lm = rmq((p<<1),l,mid,a,b);
            int rm = rmq((p<<1)|1,mid+1,r,a,b);
            st[p] = max(lm,rm);
            return st[p];
        }
    }
    
public:
    int N;
    void build(int x){
        st.assign(4*x,0);
        mark.assign(4*x,0);
        N = x;
    }
    int rmq(int a,int b){return rmq(1,0,N,a,b);}
    void range_update(int a,int b,int v){range_update(1,0,N,a,b,v);}
    
}st;

