void change(int now)
{
//	cout<<"change "<<now<<endl;
	int c=__gcd(now,mod);
	For(i,0,mod-1)ff[i]=f[i],f[i]=inf;
	For(i,0,mod-1)f[ff[i]%now]=min(f[ff[i]%now],ff[i]);
	// 前面每个均为 f[i]+K*mod
	// 关于 mod 的同余最短路 
	For(i,0,c-1){
		int len=0,t=(i+mod)%now; q[len=1]=i;
		while(t!=i)q[++len]=t,t=(t+mod)%now;
		For(j,1,len)q[j+len]=q[j]; len=len*2;
		For(j,2,len)f[q[j]]=min(f[q[j]],f[q[j-1]]+mod);
	}mod=now;
}
void solve(int k,int d,int sz) //k,k+d, ...
{
	if(d<0)return;
	int c=__gcd(k,d);
	change(k); 
//	cout<<"solve "<<k<<' '<<d<<' '<<sz<<endl;
	For(i,0,c-1)
	{
		int len=0,t=(i+d)%k,pos=1; q[len=1]=i;
		while(t!=i)q[++len]=t,t=(t+d)%k;
		For(j,1,len)if(f[q[j]]<f[q[pos]])pos=j;
		For(j,pos,len)p[j-pos+1]=q[j];
		For(j,1,pos-1)p[j+len-pos+1]=q[j];
//		For(j,1,len)cout<<p[j]<<' ';puts("");
		int l=1,r=1;
		q[1]=1,val[1]=f[p[1]]-d;
		For(j,2,len){
			int u=p[j];
			while(l<=r&&q[l]<j-sz)l++;
//			cout<<"l r"<<l<<' '<<r<<endl;
			if(l<=r) f[u]=min(f[u],val[l]+j*d+k);
			while(l<=r&&val[r]>=f[u]-j*d)r--;
			q[++r]=j,val[r]=f[u]-j*d;
		}
	}
}
