            if(S[e].size()==2)cnt3++;
            else if(S[e].size()==1)(((A[0]==S[e][0])==op)?cnt1:cnt2)++;
            op^=1;
        }
    }
    if(cnt1>cnt2)std::swap(cnt1,cnt2);
    if(cnt1+cnt3<=cnt2)ans+=cnt1+cnt3;
    else ans+=(cnt1+cnt2+cnt3)/2;
