    uint ans=0;
    for(uint i=0;i<cnt;i++)W[Back[i]]=0;
    for(uint i=cnt-1,p;i;i--){
        p=Back[i];
        if(Op[p]==1)_max(W[Fath[p]],W[p]+1),ans++;
        else if(Op[p]==2)_max(W[Fath[p]],W[p]-1);
        else if(W[p]+1+Dep[Fath[p]]<=v)_max(W[Fath[p]],W[p]+1),ans++;
        else _max(W[Fath[p]],W[p]-1);
    }
    return ans;
}
uint solve3(uint id){
    uint rot=V[id][0];
    dfs2(rot,-1),Op[rot]=0;
    for(auto p:V[id])if(p!=rot)for(auto e:Edge[p])if(!(T[e][0]^T[e][1]^p^Fath[p])){
        uint a=0;
        for(auto s:S[e])if(s==p)a|=1;else a|=2;
        Op[p]=a;
