            Edge[T[i][0]].push_back(i);
            Edge[T[i][1]].push_back(i);
        }
        else C[T[i][0]]=i;
    }
    for(uint i=0;i<m;i++)if(!~Id[i])Siz[tp]=Cnt1[tp]=Cnt2[tp]=0,V[tp].clear(),dfs(i),tp++;
    for(uint i=0;i<n;i++)if(T[i].size()==1)Cnt1[Id[T[i][0]]]++;else Cnt2[Id[T[i][0]]]++;
    for(uint i=0;i<tp;i++)if(Cnt1[i]+Cnt2[i]>Siz[i]){puts("-1");return;}
    {
