			if (l & 1) ans += sum[l ++];
			if (r & 1) ans += sum[-- r];
		}
		return ans;
	}
} segt[65];

int qp(int x, int n) {
	return !n ? 1 : 1LL * qp(1LL * x * x % mod, n >> 1) * (n & 1 ? x : 1) % mod;
}

