inline int MG(int x,int y)
{
	//if (!(x&&y)) return x|y;
	if (!x) return y;
	if (!y) return x;
	int d=t++;
	if (a[x].v>a[y].v)
		a[d]=a[x],a[d].r=MG(a[x].r,y);
	else
		a[d]=a[y],a[d].l=MG(x,a[y].l);
	updata(d);
	return d;
}

inline int SL(int x,int y)
{
	if (a[y].pd<a[x].pd)
		return SL(a[x].l,y);
	else
	{
		if (x==y&&!a[x].r)
			return x;
		int d=t++;
		a[d]=a[x],
