		a[d]=a[x],
		a[d].l=x==y?0:SR(a[x].l,y),
		updata(d);
		return d;
	}
}

inline LL cross(int a,int b,int w)
{
	return (LL)(P[a].x-P[w].x)*(P[b].y-P[w].y)-(LL)(P[b].x-P[w].x)*(P[a].y-P[w].y);
}

inline double CC(point a,point b,point c,point d)
{
	int dx1=a.x-b.x,dy1=a.y-b.y;
	int dx2=c.x-d.x,dy2=c.y-d.y;
	LL k1=(LL)dy1*dx2,k2=(LL)dy2*dx1;
	return ((double)k1*a.x-(double)k2*c.x+(double)(c.y-a.y)*dx1*dx2)/(k1-k2);
}

inline void find(int x,int y,int &A,int &B)
{
	bool l1=a[x].l&&cross(a[a[x].l].pr,a[y].pd,a[x].pd)<0,
		 r1=a[x].r&&cross(a[a[x].r].pl,a[y].pd,a[x].pd)<0,
		 l2=a[y].l&&cross(a[a[y].l].pr,a[x].pd,a[y].pd)>0,
		 r2=a[y].r&&cross(a[a[y].r].pl,a[x].pd,a[y].pd)>0;
	if (!(l1||r1||l2||r2))
	{
		A=x,B=y;
		return;
	}
	if (!(l1||r1))
		if (l2)
			return (void) find(x,a[y].l,A,B);
		else
			return (void) find(x,a[y].r,A,B);
	if (!(l2||r2))
		if (l1)
			return (void) find(a[x].l,y,A,B);
		else
			return (void) find(a[x].r,y,A,B);
	if (l1&&l2) return (void) find(a[x].l,y,A,B);
	if (r1&&r2) return (void) find(x,a[y].r,A,B);
	if (l1&&r2) return (void) find(a[x].l,a[y].r,A,B);
	if (CC(P[a[x].pd],P[a[a[x].r].pl],P[a[y].pd],P[a[a[y].l].pr])>P[a[x].pr].x)
		return (void) find(x,a[y].l,A,B);
	else
		return (void) find(a[x].r,y,A,B);
}

inline int Del(int x)
{
	if (a[x].l) return a[x].r;
	int d=t++;
	a[d]=a[x];
