using std::vector;
const int N = 3e5 + 5;
const int M = 15e4 + 5;
const int Maxn = 0x3f3f3f3f;
const int Minn = -0x3f3f3f3f;
int n, m, w, h, qr, rt, tw;
int cnt[N], len[N], tag[N], cur[N], que[N], ans[N];
int dis[N], p[N][2], maxp[N][2], minp[N][2];

#define sL s << 1
#define sR s << 1 | 1

struct point
{
	int l, r, d, u, t;

	point() {}
	point(int L, int R, int D, int U, int T):
		l(L), r(R), d(D), u(U), t(T) {}

	inline bool check_in(int s) const 
	{
		return minp[s][0] >= l && maxp[s][0] <= r
		    && minp[s][1] >= d && maxp[s][1] <= u;
	}

	inline bool check_out(int s) const
	{
		return minp[s][0] > r || maxp[s][0] < l 
		    || minp[s][1] > u || maxp[s][1] < d;
	}
};
vector<point> v[N];

template <class T>
inline T Min(T x, T y) {return x < y ? x : y;}
template <class T>
inline T Max(T x, T y) {return x > y ? x : y;}
template <class T>
inline void CkMin(T &x, T y) {x > y ? x = y : 0;}

inline void addTag(int s, int v)
{
	if (len[s] == cnt[s])
		return ;
	CkMin(dis[s], v);
	CkMin(tag[s], v);
}

inline void downDate(int s)
{
	if (tag[s] != Maxn)
	{
		addTag(sL, tag[s]);
		addTag(sR, tag[s]);
		tag[s] = Maxn;
	}
}

inline void Update1(int s)
{
	dis[s] = Min(dis[sL], dis[sR]);
	cnt[s] = cnt[sL] + cnt[sR];
}

inline void Update2(int s)
{
	maxp[s][0] = Max(maxp[sL][0], maxp[sR][0]);
	minp[s][0] = Min(minp[sL][0], minp[sR][0]);
	maxp[s][1] = Max(maxp[sL][1], maxp[sR][1]);
	minp[s][1] = Min(minp[sL][1], minp[sR][1]); 
}

inline bool cmp(const int &x, const int &y)
{
	return p[x][tw] < p[y][tw];
}

inline void Build(int s, int l, int r, int w)
{
	len[s] = r - l + 1;
	tag[s] = Maxn;
	if (l == r)
	{
		if (cur[l] == 1)
			dis[s] = 0;
		else 
			dis[s] = Maxn;
		maxp[s][0] = minp[s][0] = p[cur[l]][0];
		maxp[s][1] = minp[s][1] = p[cur[l]][1];
		return ;
	}

	int mid = l + r >> 1;
	tw = w;
	std::nth_element(cur + l, cur + mid, cur + r + 1, cmp);

	Build(sL, l, mid, w ^ 1);
	Build(sR, mid + 1, r, w ^ 1);	
	Update1(s);
	Update2(s);
}

inline void Modify(int s, const point &a, int v)
{
	if (len[s] == cnt[s] || a.check_out(s) || tag[s] <= v)
		return ;
	if (a.check_in(s))
		return addTag(s, v);

	downDate(s);
	Modify(sL, a, v);
	Modify(sR, a, v);
	Update1(s);
}

inline int Find(int s, int l, int r)
{
	if (l == r)
	{
		int x = cur[l];
		ans[x] = dis[s];
		cnt[s] = 1;
		dis[s] = Maxn;
		maxp[s][0] = maxp[s][1] = Minn;
		minp[s][0] = minp[s][1] = Maxn;
		return cur[l];
	}
	downDate(s);

	int mid = l + r >> 1, id;
	if (dis[sL] == dis[s])
		id = Find(sL, l, mid);
	else 
		id = Find(sR, mid + 1, r);
	Update1(s);
	Update2(s);
	return id;
}

int main()
{	
	read(n); read(m); read(w); read(h);
	for (int i = 1; i <= n; ++i)
		read(p[i][0]), read(p[i][1]);
	
	for (int i = 1; i <= n; ++i)
		cur[i] = i;
	Build(1, 1, n, 0);

	int p, t, l, r, d, u;
	for (int i = 1; i <= m; ++i)
	{
		read(p); read(t);
		read(l); read(r); read(d); read(u);
		v[p].push_back(point(l, r, d, u, t));
	}
	for (int i = 1; i <= n; ++i)
	{
		int x = Find(1, 1, n);
		for (int j = 0, jm = v[x].size(); j < jm; ++j)
			Modify(1, v[x][j], ans[x] + v[x][j].t);
	}
	for (int i = 2; i <= n; ++i)
		put(ans[i]), putchar('\n');
	return 0;	
}

