inline void FWT(int *a, int n, int type) {
    for (int p = 1; p < n; p <<= 1)
        for (int i = 0; i < n; i++) if (i & p) {
            int h1 = a[i - p], h2 = a[i];
            a[i - p] = Mod(h1 + h2);
            a[i] = Mod(h1 - h2 + mod);
        }
    if (type == -1) {
        int inv = power(n, mod - 2);
        for (int i = 0; i < n; i++) a[i] = 1ll * a[i] * inv % mod;
    }
}
