typedef long long ll;
inline int read() {
	int f=1,sum=0;
	char x=getchar();
	for(;(x<'0'||x>'9');x=getchar()) if(x=='-') f=-1;
	for(;x>='0'&&x<='9';x=getchar()) sum=sum*10+x-'0';
	return f*sum;
}

const int M=1e6+10;
int n,m,h,mod;
int a,b,c,f[M],g[M],s[M],inv[M];

inline int qpow(int x,int ci) {
	int sum=1;
	for(;ci;ci>>=1,x=1ll*x*x%mod)
		if(ci&1) sum=1ll*x*sum%mod;
	return sum;
}

inline void inc(int &x,int y) {x+=y,x-=x>=mod?mod:0;}

inline int cal1() {
	int ans=0;
	
	if(b==1&&h==1) {
		int t=1,k=0,a_i=1;
		FOR2(n,1,i) {
			t=1ll*t*(m+n-i)%mod*inv[n-i+1]%mod;
			inc(k,1ll*t*a_i%mod);
			a_i=1ll*a*a_i%mod;
			inc(ans,1ll*k*f[i]%mod);
		}
	}
	else {
		int k1=0,k2=0;
		int x=1ll*h*b%mod;
		int c=qpow(x,m+1);
		int p3=qpow((x+mod-1)%mod,mod-2);
		int p4=qpow(h,(1ll*n*m-1)%(mod-1)),p5=qpow(qpow(h,m),mod-2);
		
		FOR2(n,1,i) {
			if(i!=n) k2=1ll*(c-k2+mod)*p3%mod;
			else k2=1ll*(qpow(x,m+1)-x+mod)*qpow((x+mod-1)%mod,mod-2)%mod;
			k1=1ll*(k1+1ll*p4*k2%mod)*p5%mod;
			inc(ans,1ll*k1*f[i]%mod);
			p4=1ll*p4*a%mod;
			c=1ll*c*(m+n-i)%mod*inv[n-i+1]%mod;
		}
	}
	
	return ans;
}

inline int cal2() {
	if(!c) return 0;
 	if(b==1&&h==1) {
 		g[0]=m;
 		for1(1,n,i) g[i]=1ll*g[i-1]*(m+i)%mod*inv[i+1]%mod;
 	}
 	else {
 		int x=1ll*b*h%mod;
 		g[0]=1ll*(qpow(x,m)+mod-1)*qpow(x-1,mod-2)%mod;
 		int c=qpow(x,m);
 		int p1=qpow((x+mod-1)%mod,mod-2);
 		for1(1,n,i) {
 			c=1ll*c*(i+m-1)%mod*inv[i]%mod;
 			g[i]=1ll*(c-g[i-1]+mod)*p1%mod;
 		}
 	}
 	
 	/*
 	for1(0,n,x) {
 		int sum=0;
 		for1(0,m-1,i) inc(sum,1ll*qpow(b,i)*js[i+x]%mod*ni[x]%mod*ni[i]%mod*qpow(h,i)%mod);
 		cout<<sum<<" "<<g[x]<<endl;
 	}
 	*/
 	
 	if(b==1) {
 		for1(0,n,i) s[i]=g[i+1];
 	}
 	else {
 		if(h!=1) {
 			int x=b;
 			if(x==1) s[0]=1ll*m*qpow(h,m)%mod;
 			else s[0]=1ll*(qpow(b,m)-1+mod)*qpow((b+mod-1)%mod,mod-2)%mod*qpow(h,m)%mod;
 			
 			x=1ll*h*b%mod;
 			inc(s[0],mod-1ll*(qpow(x,m)+mod-1)*qpow((x+mod-1)%mod,mod-2)%mod);
 			
 			s[0]=1ll*s[0]*qpow((h+mod-1)%mod,mod-2)%mod;
 		}
 		else {
 			if(b==1) s[0]=(1ll*m*m%mod-1ll*m*(m-1)%mod*inv[2]%mod+mod)%mod;
 			else {
 				s[0]=1ll*m*(qpow(b,m)+mod-1)%mod;
 				
 				inc(s[0],mod-1ll*(m-1)*qpow(b,m)%mod);
 				inc(s[0],1ll*(qpow(b,m)-b+mod)*qpow(b-1,mod-2)%mod);
 				s[0]=1ll*s[0]*qpow((b+mod-1)%mod,mod-2)%mod;
 			}
 		}
 		int p1=qpow((b+mod-1)%mod,mod-2);
 		for1(1,n,i) s[i]=(1ll*b*g[i]%mod-s[i-1]+mod)*p1%mod;
 	}
 	
 	
	/*
	for1(0,n,x) {
		int sum=0;
		for1(0,m-1,i) {
			inc(sum,1ll*js[i+x]*ni[x]%mod*ni[i]%mod*qpow(b,i)%mod*(qpow(h,m)-qpow(h,i)+mod)%mod*qpow(h-1,mod-2)%mod);
 		}
 		//s[x]=sum;
 		cout<<sum<<" "<<s[x]<<endl;
 	}
 	*/
 	
 	int k=0,ans=0;
 	int p1=1,p2=1,p3=qpow(h,m);
 	for1(1,n,i) {
 		inc(k,1ll*p1*s[i-1]%mod);
 		inc(ans,1ll*k*p2%mod);
 		p1=1ll*a*p1%mod;
 		p2=1ll*p2*p3%mod;
 	}
 	return 1ll*c*ans%mod;
}

int main () {
	//freopen("a.in","r",stdin);
	read();
	n=read(),m=read(),h=read(),mod=read(),a=read(),b=read(),c=read();
	for1(1,n,i) f[i]=read();
	
	inv[1]=1;
	for1(2,M-5,i) inv[i]=1ll*(mod-mod/i)*inv[mod%i]%mod;

	cout<<(cal1()+cal2())%mod<<endl;
}

