            re[s[i].pla]+=(long long)v[c[glca[s[i].pla]]]*w[num[c[glca[s[i].pla]]]+1];
    }
    for(int i=1;i<=numS;i++)
        printf("%lld\n",re[i]);
    return 0;
}

