const int MAXN = 50 + 5;

int cnt, ans;
bool ok[MAXN];
std::pair < int, int > pos[MAXN], dir[MAXN];

void DFS(int cur, int res) {
  if (res > ans)
    return;
  if (cur > cnt) {
    ans = res;
    return;
  }
  if (!pos[cur].F || !pos[cur].S) {
    ok[cur] = 0;
    DFS(cur + 1, res);
    return;
  }
  ok[cur] = 1;
  int f0 = 0, f1 = 0;
  dir[cur].S = 0;
  FOR(i, 1, cur) {
    if (!ok[i])
      continue;
    if (pos[i].S > pos[cur].S)
      ++ f1;
    else if (pos[i].S > pos[cur].F)
      f0 += !dir[i].S, f1 += dir[i].S;
  }
  dir[cur].F = f0 > f1;
  DFS(cur + 1, res + mymin(f0, f1));
  f0 = 0, f1 = 0;
  dir[cur].S = 1;
  FOR(i, 1, cur) {
    if (!ok[i])
      continue;
    if (pos[i].S > pos[cur].S)
      ++ f0;
    else if (pos[i].S > pos[cur].F)
      f0 += !dir[i].S, f1 += dir[i].S;
  }
  dir[cur].F = f0 > f1;
  DFS(cur + 1, res + mymin(f0, f1));
}

int main() {
  int T;
  scanf("%d", &T);
  while (T --) {
    memset(pos, 0, sizeof pos);
    cnt = 0;
    int n;
    scanf("%d", &n);
    For(i, 1, n) {
      int x;
      scanf("%d", &x);
      chkmax(cnt, x);
      if (pos[x].F)
        pos[x].S = i;
      else
        pos[x].F = i;
    }
    std::sort(pos + 1, pos + cnt + 1);
    ans = INF;
    DFS(1, 0);
    printf("%d\n", ans);
  }
  return 0;
}

