using namespace std;
typedef __uint128_t u128;
inline u128 read() {
    static char buf[100];
    scanf("%s", buf);
    // std::cin >> buf;
    u128 res = 0;
    for(int i = 0;buf[i];++i) {
        res = res << 4 | (buf[i] <= '9' ? buf[i] - '0' : buf[i] - 'a' + 10);
    }
    return res;
}
inline void output(u128 res) {
    if(res >= 16)
        output(res / 16);
    putchar(res % 16 >= 10 ? 'a' + res % 16 - 10 : '0' + res % 16);
	//std::cout.put(res % 16 >= 10 ? 'a' + res % 16 - 10 : '0' + res % 16);
}
const int S=700;
int n,q,l,r,op,b[300001],d[300001];
bool zr[300001];
u128 a[300001],v,sm[300001],tg[300001],full,nw[300001];
bool pdn(int x)
{
	x=b[x];
	if(tg[x]==full)
	return false;
	sm[x]=0;
	u128 tmp=tg[x];
	for(int i=x;i<=d[x];i++)
	{
		a[i]&=tmp;
		sm[x]+=a[i];
	}
	tg[x]=full;
	return true;
}
void pup(int x)
{
	x=b[x];
	nw[x]=sm[x]=00;
	for(int i=x;i<=d[x];i++)
	{
		nw[x]|=a[i];
		sm[x]+=a[i];
	}
	if(nw[x]==0)
	zr[x]=true;
	return ;
}
int main()
{
	//freopen("ex_machine3.in","r",stdin);
	//freopen("ex_machine3.ans","w",stdout);
	scanf("%d%d",&n,&q);
	for(int i=1;i<=n;i++)
	{
		a[i]=read();
		b[i]=(i-1)/S*S+1;
		d[b[i]]=i;
		sm[b[i]]+=a[i];
		nw[b[i]]|=a[i];
	}
	full--;
	for(int i=1;i<=n;i++)
	if(i==b[i])
	tg[i]=full;
	while(q--)
	{
		scanf("%d%d%d",&op,&l,&r);
		if(op!=3)
		v=read();
		
		if(op==1)
		{
			if(v==1) continue;
			if(b[l]==b[r])
			{
				pdn(l);
				for(int i=l;i<=r;i++)
				a[i]/=v;
				pup(l);
				continue;
			}
			pdn(l);
			for(int i=l;i<=d[b[l]];i++)
			a[i]/=v;
			pup(l);
			pdn(r);
			for(int i=b[r];i<=r;i++)
			a[i]/=v;
			pup(r);
			l=d[b[l]]+1;
			r=b[r];
			while(l!=r)
			{
				if(zr[l]==false)
				{
					pdn(l);
					for(int i=l;i<=d[l];i++)
					a[i]/=v;
					pup(l);
				}
				l=d[l]+1;
			}
		}
		if(op==2)
		{
			if(b[l]==b[r])
			{
				pdn(l);
				for(int i=l;i<=r;i++)
				a[i]&=v;
				pup(l);
				continue;
			}
			pdn(l);
			for(int i=l;i<=d[b[l]];i++)
			a[i]&=v;
			pup(l);
			pdn(r);
			for(int i=b[r];i<=r;i++)
			a[i]&=v;
			pup(r);
			l=d[b[l]]+1;
			r=b[r];
			while(l!=r)
			{
				if(zr[l]==false&&(nw[l]!=(nw[l]&v)))
				{
					nw[l]&=v;
					tg[l]&=v;
				}
				l=d[l]+1;
			}
		}
		if(op==3)
		{
			if(b[l]==b[r])
			{
				pdn(l);
				pup(l);
				u128 ans=0;
				for(int i=l;i<=r;i++)
				ans+=a[i];
				output(ans);
				putchar('\n');
				continue;
			}
			u128 ans=0;
			pdn(l);
			pup(l);
			pdn(r);
			pup(r);
			for(int i=l;i<=d[b[l]];i++)
			ans+=a[i];
			for(int i=b[r];i<=r;i++)
			ans+=a[i];
			l=d[b[l]]+1;
			r=b[r];
			while(l!=r)
			{
				if(zr[l]==false)
				{
					pdn(l);
					ans+=sm[l];
				}
				l=d[l]+1;
			}
			output(ans);
			putchar('\n');
		}
	}
	return 0;
}

#include<cstdio>
#include<algorithm>
#include<cmath>
using namespace std;
typedef long long ll;
const int maxk=1e7;
const int mod=998244353;
int ksm(ll ta,int tp,int s=1){
	for(;tp;ta=ta*ta%mod,tp>>=1) if(tp&1) s=ta*s%mod;
	return s;
}
bool p[maxk+5];
int np[maxk+5],ps;
int kp[maxk+5];
int invi[maxk+5];
int fac[maxk+5],ifac[maxk+5];
void prep(int len,int n){
	p[0]=p[1]=1; kp[0]=n==0; kp[1]=1;
	for(int i=2;i<=len;i++){
		if(!p[i]) np[++ps]=i,kp[i]=ksm(i,n);
		for(int j=1;1ll*i*np[j]<=len;j++){
			p[i*np[j]]=1;
			kp[i*np[j]]=1ll*kp[i]*kp[np[j]]%mod;
			if(i%np[j]==0) break;
		}
	}
	fac[0]=1;
	for(int i=1;i<=len;i++) fac[i]=1ll*fac[i-1]*i%mod;
	ifac[len]=ksm(fac[len],mod-2);
	for(int i=len;i;i--) ifac[i-1]=1ll*ifac[i]*i%mod;
	for(int i=1;i<=len;i++) invi[i]=1ll*ifac[i]*fac[i-1]%mod;
}
int sqr(int ta){ return 1ll*ta*ta%mod; }
int k;
ll n;
int f[maxk+5],g[maxk+5];
ll ans;
int main(){
	scanf("%d %lld",&k,&n); k--;
	prep(max(k,10),(n-1)%(mod-1));
	int inv2=ksm(2,mod-1-k);
	f[k]=1ll*inv2*ifac[k]%mod;
	for(int i=k-2;i>=0;i-=2)
		f[i]=-1ll*sqr(1ll*invi[k-i]*(i+2+k)%mod)*f[i+2]%mod;
	for(int i=k;i>0;i-=2) ans+=1ll*f[i]*kp[i]%mod;
	ans+=1ll*f[0]*kp[0]*invi[2]%mod;
	ans=ans%mod*(n%mod)%mod;
	inv2=inv2*2%mod;
	for(int i=0,tmp;2*i<k;i++){
		tmp=1ll*ifac[i]*ifac[k-1-i]%mod*inv2%mod;
		g[k-1-2*i]=i&1?-tmp:tmp;
	}
	for(int i=k+1;i>=2;i-=2) g[i]=(g[i]+g[i-2])%mod;
	for(int i=2;i<=k+2;i++) g[i]=(g[i]-2ll*(i+k)*f[i]-2ll*(i-k-2)*f[i-2])%mod;
	ll ts=0;
	for(int j=1,tmp;j<=k;j++){
		tmp=1ll*ifac[k-j]*ifac[j]%mod*invi[j]%mod;
		ts+=j&1?-tmp:tmp;
	}
	f[k]=ts%mod*inv2%mod*invi[2]%mod;
	for(int i=k-1;i>0;i--)
		f[i]=1ll*(g[i+2]-1ll*sqr(i+k+2)*f[i+2])%mod*sqr(invi[k-i])%mod;
	for(int i=k;i;i--) ans+=1ll*kp[i]*f[i]%mod*i%mod;
	printf("%lld\n",(ans*2%mod+mod)%mod);
	return 0;
}

