namespace pb_ds
{   
	// 输入输出优化模板从此开始
	namespace io
	{
		const int MaxBuff = 1 << 15;
		const int Output = 1 << 24;
		char B[MaxBuff], *S = B, *T = B;
		//#define getc() getchar()
		#define getc() ((S == T) && (T = (S = B) + fread(B, 1, MaxBuff, stdin), S == T) ? 0 : *S++)
		char Out[Output], *iter = Out;
		IL void flush()
		{
			fwrite(Out, 1, iter - Out, stdout);
			iter = Out;
		}
	}
	
	template<class Type> IL Type read()
	{
		using namespace io;
		RG char ch; RG Type ans = 0; RG bool neg = 0;
		while(ch = getc(), (ch < '0' || ch > '9') && ch != '-')     ;
		ch == '-' ? neg = 1 : ans = ch - '0';
		while(ch = getc(), '0' <= ch && ch <= '9') ans = ans * 10 + ch - '0';
		return neg ? -ans : ans;
	}
	template<class Type> IL void print(RG Type x, RG char ch = '\n')
	{
		using namespace io;
		if(!x) *iter++ = '0';
		else
		{
			if(x < 0) *iter++ = '-', x = -x;
			static int S2[100]; RG int t = 0;
			while(x) S2[++t] = x % 10, x /= 10;
			while(t) *iter++ = '0' + S2[t--];
		}
		*iter++ = ch;
	}
	// 输入输出优化模板到此结束
	const int MaxN = 100010;
	const int mod = 10007;
	int d[MaxN];
	int A[50], B[50], R[50], p[MaxN], coe[20][MaxN], pwr[15][MaxN], pre[MaxN][20][15], P;
	
	inline int inv(RG int i) {return i == 1 ? 1 : mod - (mod / i) * inv(mod % i) % mod;}
	
	IL void FMT0(RG int *A, RG int N)
	{
		for(RG int i = 0, p, q, u; i != P; ++i)
			for(p = pb_ds::p[i], q = 1, u = N / p; q <= u; ++q) 
				(A[p * q] += A[q]) %= mod;
	}
	IL void FMT1(RG int *A, RG int N)
	{
		for(RG int i = 0, p, q; i != P; ++i)
			for(p = pb_ds::p[i], q = N / p; q; --q)
				(A[p * q] -= A[q]) %= mod;
	}

	IL void main()
	{
		RG int (*F)() = read<int>;
		RG const int MaxNum = 100000;
		RG const int MaxA = 18;
		RG const int MaxN = 11;
		RG int j, U, D;
		For(i, 2, MaxNum)
		{
			if(!d[i]) d[i] = p[P++] = i;
			D = d[i], U = dmin(D, ___u / i);
			for(j = 0; j != P && p[j] <= U; ++j)
				d[i * p[j]] = p[j];
		}
		For(i, 1, MaxNum) coe[0][i] = pwr[0][i] = 1;
		For(k, 1, MaxA)
		{
			RG int *p = coe[k], *q = coe[k - 1];
			For(i, 1, MaxNum) p[i] = i * q[i] % mod;
			if(k <= MaxN) memcpy(pwr[k], coe[k], MaxNum << 2);
		}
		For(k, 0, MaxA) FMT1(coe[k], MaxNum);
		For(v, 1, MaxNum)
		{
			For(i, 0, MaxA) For(j, 0, MaxN)
				pre[v][i][j] = (pre[v - 1][i][j] + coe[i][v] * pwr[j][v]) % mod;
		}
		
		For(__, 1, F())
		{
			RG int N = F(), K = F() - 2, M = MaxNum;
			Rep(i, 0, N) R[i] = F(), cmin(M, R[i]);
			
			memset(A + 1, 0, K << 2);
			A[0] = 1;
			RG int Fac = 1;
			For(k, 1, K) 
			{
				(Fac *= k) %= mod;
				Dor(j, 0, k - 1)
				{
					(A[j + 1] += A[j]) %= mod;
					(A[j] *= -k) %= mod;
				}
			}
			Fac = inv(Fac);
			For(j, 0, K) (A[j] *= Fac) %= mod;
			
			RG int ans = 0;
