} M;
queue <int> Q;
int EMP;
int is_right(int t) {return tr[tr[t].fa].ch[1] == t;}
int is_root(int t) {return tr[t].fa == 0 || tr[tr[t].fa].ch[0] != t && tr[tr[t].fa].ch[1] != t;}
void update(int t)
{
	if (!tr[t].tp)
	{
		tr[t].sum_cir = tr[tr[t].ch[0]].sum_cir + tr[tr[t].ch[1]].sum_cir + tr[tr[t].cir].sum_cir;
		tr[t].sum_A = tr[tr[t].ch[0]].sum_A + tr[tr[t].ch[1]].sum_A + tr[tr[t].cir].sum_A + tr[t].wA;
		tr[t].min_B = min(min(tr[tr[t].ch[0]].min_B, tr[tr[t].ch[1]].min_B), tr[tr[t].cir].min_B);
		if (tr[t].wB) tr[t].min_B = min(tr[t].min_B, tr[t].wB);
	}
	else
	{
		tr[t].sum_cir = min(tr[tr[t].ch[0]].sum_cir, tr[tr[t].ch[1]].sum_cir) + 1;
		tr[t].sum_A = min(tr[tr[t].ch[0]].sum_A, tr[tr[t].ch[1]].sum_A);
		if (tr[tr[t].ch[0]].sum_A == tr[tr[t].ch[1]].sum_A) tr[t].min_B = -1;
		else tr[t].min_B = tr[tr[t].ch[0]].sum_A < tr[tr[t].ch[1]].sum_A? tr[tr[t].ch[0]].min_B: tr[tr[t].ch[1]].min_B;
	}
}
void rotate(int t)
{
	int k = is_right(t), b = tr[t].ch[!k], a = tr[t].fa, o = tr[a].fa;
	tr[a].ch[k] = b; tr[t].ch[!k] = a; 
	if (!is_root(a)) tr[o].ch[is_right(a)] = t;
	else if (tr[o].cir == a) tr[o].cir = t;
	if (b) tr[b].fa = a; tr[a].fa = t; tr[t].fa = o;
	update(a); update(t);
}
void reverse(int t)
{
	swap(tr[t].ch[0], tr[t].ch[1]);
	if (tr[t].cir) swap(tr[tr[t].cir].ch[0], tr[tr[t].cir].ch[1]);
	tr[t].rev ^= 1;
}
void add(int t, int d)
{
	if (tr[t].wB) tr[t].wB += d;
	if (tr[t].min_B != INF) tr[t].min_B += d;
	if (t) tr[t].tag_adB += d;
}
void push_down(int t)
{
	if (tr[t].rev)
	{
		if (tr[t].ch[0]) reverse(tr[t].ch[0]);
		if (tr[t].ch[1]) reverse(tr[t].ch[1]);
		tr[t].rev = 0;
	}
	if (tr[t].tag_adB)
	{
		if (tr[t].cir) add(tr[tr[t].cir].ch[tr[tr[tr[t].cir].ch[0]].sum_A > tr[tr[tr[t].cir].ch[1]].sum_A], tr[t].tag_adB), update(tr[t].cir);
		if (tr[t].ch[0]) add(tr[t].ch[0], tr[t].tag_adB);
		if (tr[t].ch[1]) add(tr[t].ch[1], tr[t].tag_adB);
		tr[t].tag_adB = 0;
	}
}
void push_all(int t)
{
	if (!is_root(t)) push_all(tr[t].fa);
	push_down(t);
}
void push_it(int t)
{
	if (tr[t].fa) push_it(tr[t].fa);
	push_down(t);
}
int ancestor(int t)
{
	if (!is_root(t)) return ancestor(tr[t].fa); else return t;
}
void splay(int t, int &pos)
{
	push_all(t);
	while (t != pos && !is_root(t))
	{
		int a = tr[t].fa;
		if (a == pos || is_root(a));
		else if (is_right(t) == is_right(a)) rotate(a);
		else rotate(t); rotate(t);
	}
}
int find(int t, int tp)
{
	push_down(t);
	if (tr[t].ch[tp]) return find(tr[t].ch[tp], tp);
	else return t;
}
void dfs(int t)
{
	int a = ancestor(t), o = tr[a].fa;
	if (o) 
	{
		dfs(o);
		if (!tr[a].tp)
		{
			tr[o].ch[1] = a;
			update(o);
			splay(t, EMP);
		}
		else
		{
			int r = find(tr[o].ch[1], 0); splay(r, tr[o].ch[1]);
			if (tr[a].ch[0]) tr[tr[a].ch[0]].fa = r;
			if (tr[a].ch[1]) tr[tr[a].ch[1]].fa = r;
			tr[o].cir = r;
			tr[r].ch[0] = tr[a].ch[0]; tr[r].ch[1] = tr[a].ch[1];
			tr[o].ch[1] = 0;
			update(r);
			splay(t, EMP);
			if (tr[t].ch[0]) tr[tr[t].ch[0]].fa = a;
			if (tr[t].ch[1]) tr[tr[t].ch[1]].fa = a;
			tr[o].cir = a;
			tr[a].ch[0] = tr[t].ch[0]; tr[a].ch[1] = tr[t].ch[1];
			tr[t].fa = o;
			tr[t].ch[0] = 0; tr[t].ch[1] = 0; tr[o].ch[1] = t;
			update(a); update(t); update(o);
			rotate(t);
		}
	}
	else splay(t, EMP);
}
void access(int t)
{
	push_it(t);
	dfs(t);
	tr[t].ch[1] = 0;
}
void make_root(int t)
{
	access(t);
	reverse(t);
	splay(t, EMP);
}
int link(int u, int v)
{
	make_root(v);
	access(u);
	if (tr[v].fa == 0)
	{
		tr[u].ch[1] = v; tr[v].fa = u;
		update(u);
	}
	else
	{
		splay(v, EMP);
		splay(u, tr[v].ch[1]);
		if (tr[tr[u].ch[0]].sum_cir + tr[tr[u].cir].sum_cir) 
			return 0;
		int nw = ++ tl;
		tr[v].ch[1] = nw; tr[nw].fa = v; tr[nw].ch[1] = u; tr[u].fa = nw;
		int nc = ++ tl;
		tr[nw].cir = nc; tr[nc].fa = nw; tr[nc].ch[0] = tr[u].ch[0]; tr[tr[u].ch[0]].fa = nc;
		tr[nc].tp = 1;
		tr[u].ch[0] = 0;
		update(u); update(nc); update(nw); update(v);
	}
	return 1;
}
void cut(int u, int v)
{
	make_root(v);
	access(u);
	splay(v, EMP);
	splay(u, tr[v].ch[1]);
	if (!tr[tr[u].ch[0]].sum_cir)
	{
		tr[v].ch[1] = tr[u].fa = 0; 
		update(v);
	}
	else
	{
		int nw = tr[tr[u].ch[0]].cir; tr[u].cir = 0;
		tr[u].ch[0] = tr[nw].ch[0]; tr[u].ch[1] = tr[nw].ch[1];
		if (tr[nw].ch[0]) tr[tr[nw].ch[0]].fa = u;
		if (tr[nw].ch[1]) tr[tr[nw].ch[1]].fa = u;
		update(u); update(v);
	}
}
pI query(int u, int v)
{
	if (u == v) return make_pair(0, INF);
	make_root(v);
	access(u);
	if (!tr[v].fa) return make_pair(-1, -1);
	splay(v, EMP);
	splay(u, tr[v].ch[1]);
	return make_pair(tr[tr[u].ch[0]].sum_A + tr[tr[u].cir].sum_A, min(tr[tr[u].ch[0]].min_B, tr[tr[u].cir].min_B));
}
int add(int u, int v, int d)
{
	if (u == v) return 1;
	make_root(v);
	access(u);
	if (!tr[v].fa) return 0;
	splay(v, EMP);
	splay(u, tr[v].ch[1]);
	if (min(tr[tr[u].ch[0]].min_B, tr[tr[u].cir].min_B) == -1) return 0;
	else add(u, d), update(v);
	return 1;
}
