	int len=strlen(s+1);
	string ans;
	Dec(i,len,0){
		if(i==len&&lyndon(s+1)){
			if(k==1){
				ans=s+1;
				break;
			}
			--k;
		}
		For(j,i==len?0:s[i+1]-'a'+1,25){
			string t=string(s+1,s+i+1)+char(j+'a');
			ll cnt=get(count(t));
			if(k>cnt){
				k-=cnt;
			}else{
				ans=t;
				break;
			}
		}
		if(ans.size()) break;
	}
	if(!ans.size()){
		cout<<"-1\n";
		return 0;
	}
	while(k>1){
		if(lyndon(ans)){
			if(k==1) break;
			--k;
		}
		bool flg=0;
		For(j,0,25){
			string t=ans+char(j+'a');
			ll cnt=get(count(t));
			if(k>cnt){
				k-=cnt;
			}else{
				flg=1;
				ans.push_back(j+'a');
				break;
			}
		}
		if(!flg){
			cout<<"-1\n";
			return 0;
		}
	}
	if(!ans.size()){
		cout<<"-1\n";
		return 0;
	}
	cout<<ans<<'\n';
	return 0;
}

